1	function csirs_printSweepTable(results, snrList)
2	%CSIRS_PRINTSWEEPTABLE  Print SNR sweep comparison table.
3	%
4	%  Columns per SNR point: RI avg | MCS avg | TP avg (Mbps) | % vs B
5	%  Rows: B (reference), C (Mode A), D (Mode B), E (eTypeII-r19)
6	%
7	%  Inputs:
8	%    results  - struct array (1 x nSNR), each element has:
9	%                 .snr          scalar
10	%                 .ri  [1x4]    avg RI  (B C D E)
11	%                 .mcs [1x4]    avg MCS (B C D E)
12	%                 .tp  [1x4]    avg TP in Mbps (B C D E)
13	%    snrList  - [1 x nSNR] SNR values in dB
14	
15	nSNR = length(snrList);
16	% ThangTQ23_128T128R_eTypeII_Rel19: added Approach E label
17	labels = {'B: SVD (ref)', 'C: Mode A   ', 'D: Mode B   ', 'E: eTypeII-r19'};
18	
19	% ── Header ───────────────────────────────────────────────────────────────
20	fprintf('\n');
21	fprintf('========================================================================================\n');
22	fprintf('       128T128R CSI FEEDBACK -- SNR SWEEP RESULTS (avg over realizations)            \n');
23	fprintf('========================================================================================\n');
24	
25	% Per-SNR column headers
26	fprintf('%-14s', 'Approach');
27	for i = 1:nSNR
28	    label = sprintf('SNR=%+ddB', snrList(i));
29	    switch snrList(i)
30	        case num2cell(-10:4);  dist = '(far)  ';
31	        otherwise
32	            if snrList(i) <= 5
33	                dist = '(far)  ';
34	            elseif snrList(i) <= 15
35	                dist = '(med)  ';
36	            else
37	                dist = '(near)';
38	            end
39	    end
40	    fprintf('  %-40s', sprintf('%s %s', label, dist));
41	end
42	fprintf('\n');
43	
44	fprintf('%-14s', '');
45	for i = 1:nSNR
46	    fprintf('  %-6s  %-6s  %-10s  %-6s', 'RI', 'MCS', 'TP(Mbps)', '% vsB');
47	end
48	fprintf('\n');
49	
50	sep = repmat('-', 1, 14 + nSNR*32);
51	fprintf('%s\n', sep);
52	
53	% ── Data rows ─────────────────────────────────────────────────────────────
54	for appIdx = 1:4   % B=1, C=2, D=3, E=4 (ThangTQ23_128T128R_eTypeII_Rel19)
55	    fprintf('%-14s', labels{appIdx});
56	    for i = 1:nSNR
57	        ri_val  = results(i).ri(appIdx);
58	        mcs_val = results(i).mcs(appIdx);
59	        tp_val  = results(i).tp(appIdx);
60	        tp_ref  = results(i).tp(1);   % B is reference
61	
62	        if appIdx == 1
63	            pct_str = '  ref ';
64	        else
65	            pct_str = sprintf('%5.1f%%', tp_val/tp_ref*100);
66	        end
67	        fprintf('  %-6.2f  %-6.1f  %-10.1f  %s', ri_val, mcs_val, tp_val, pct_str);
68	    end
69	    fprintf('\n');
70	
71	    % Separator after reference row
72	    if appIdx == 1
73	        fprintf('%s\n', sep);
74	    end
75	end
76	
77	fprintf('%s\n', sep);
78	fprintf('  RI: avg rank indicator  |  MCS: avg MCS index (1-15)  |  TP: throughput Mbps\n');
79	fprintf('  %% vsB: throughput relative to SVD upper bound\n\n');
80	
81	end
