1	function fb = csirs_feedback(carrier, csirs, H_est_full, nVar_all, slotAssign, pmiMode, cqiMode, panelDimensions, paramCombE)
2	%CSIRS_FEEDBACK  CSI feedback (RI/PMI/CQI/Cap) for Approaches B, C, D, E.
3	%
4	%  Approach B: Full 128-port SVD upper bound (ideal reference)
5	%  Approach C: Rel-19 Type I Single-Panel Mode A (TS 38.214 S5.2.2.2.1a)
6	%  Approach D: Rel-19 Type I Single-Panel Mode B (TS 38.214 S5.2.2.2.1a)
7	%  Approach E: Rel-19 Refined eTypeII 128-port (TS 38.214 S5.2.2.2.5a)
8	%              ThangTQ23_128T128R_eTypeII_Rel19
9	%
10	%  CQI for C/D/E: computed via nr5g.internal.nrCQISelect (L2SM/MIESM,
11	%  BLER threshold 10%, per TS 38.214 S5.2.2.1) — now supports Rel-19.
12	%
13	%  Inputs:
14	%    carrier      - nrCarrierConfig
15	%    csirs        - {1x4} nrCSIRSConfig objects (csirs{1} used for C/D/E)
16	%    H_est_full   - [K x 28 x nRx x 128] estimated channel
17	%    nVar_all     - [1x4] noise variance per resource
18	%    slotAssign   - [1x4] slot index per resource
19	%    pmiMode      - (optional) 'Subband' (default) or 'Wideband'
20	%    cqiMode      - (optional) 'Wideband' (default) or 'Subband'
21	%                   When 'Subband': fb.cqi_C/D/E are vectors [1+numSB x 1]
22	%                   Row 1 = wideband CQI, rows 2..end = per-subband CQI
23	%    panelDimensions - (optional) [Ng N1 N2], default [1 16 4]
24	%    paramCombE   - (optional) ParameterCombination for Approach E, default 1
25	%                   Valid: 1-8 per TS 38.214 Table 5.2.2.2.5-1
26	%                   PC 7/8: L=6, maxRank capped at 2 (pv for rank 3/4 = "-")
27	%
28	%  Output:
29	%    fb - struct:
30	%           .ri_B,  .cqi_B,  .cap_B,  .W_B
31	%           .ri_C,  .cqi_C,  .cap_C,  .W_C,  .sinrPerRE_C
32	%           .ri_D,  .cqi_D,  .cap_D,  .W_D,  .sinrPerRE_D
33	%           .ri_E,  .cqi_E,  .cap_E,  .W_E,  .sinrPerRE_E
34	%         cqi_C/D/E: wideband scalar (CQIMode='Wideband')
35	%                    or [1+numSB x 1] vector (CQIMode='Subband'),
36	%                    row 1 = wideband, rows 2..end = per-subband
37	%                    Note: Mode D beam is always wideband (spec constraint),
38	%                    but per-subband CQI with that beam is still valid.
39	
40	if nargin < 6 || isempty(pmiMode)
41	    pmiMode = 'Subband';
42	end
43	pmiMode = validatestring(pmiMode, {'Subband','Wideband'});
44	
45	if nargin < 7 || isempty(cqiMode)
46	    cqiMode = 'Wideband';
47	end
48	cqiMode = validatestring(cqiMode, {'Wideband','Subband'});
49	
50	nRxAntennas  = size(H_est_full, 3);
51	nTxAntennas  = size(H_est_full, 4);
52	nResources   = length(csirs);
53	nPortsPerRes = nTxAntennas / nResources;
54	
55	if nargin < 8 || isempty(panelDimensions)
56	    panelDimensions = [1, 16, 4];   % fallback: [Ng, N1=Nh, N2=Nv]
57	end
58	
59	% ThangTQ23_128T128R_eTypeII_Rel19: ParameterCombination for Approach E
60	if nargin < 9 || isempty(paramCombE)
61	    paramCombE = 5;   % L=4, pv(v=1..4)=1/4, β=1/4 — supports rank 1~4
62	end
63	nSymPerSlot  = carrier.SymbolsPerSlot;
64	
65	% ── Wideband channel matrix H_wb [nRx x nTx] ─────────────────────────────
66	H_wb = zeros(nRxAntennas, nTxAntennas);
67	for r = 1:nResources
68	    pS = (r-1)*nPortsPerRes + 1;  pE = r*nPortsPerRes;
69	    sS = slotAssign(r)*nSymPerSlot + 1;
70	    sE = (slotAssign(r)+1)*nSymPerSlot;
71	    H_wb(:, pS:pE) = squeeze(mean(H_est_full(:, sS:sE, :, pS:pE), [1 2]));
72	end
73	
74	nVar_wb = mean(nVar_all);
75	
76	% Broadcast H_wb to [K x L x nRx x nTx] for nrPMIReport / nrCQISelect
77	carrier.NSlot = 0;
78	nSC = carrier.NSizeGrid * 12;
79	H_4d = repmat(reshape(H_wb, 1, 1, nRxAntennas, nTxAntennas), ...
80	              [nSC, carrier.SymbolsPerSlot, 1, 1]);
81	
82	% ── Subband size per TS 38.214 Table 5.2.1.4-2 (smallest valid value) ────
83	nSizeBWP = carrier.NSizeGrid;
84	if nSizeBWP >= 145
85	    subbandSize = 16;
86	elseif nSizeBWP >= 73
87	    subbandSize = 8;
88	elseif nSizeBWP >= 24
89	    subbandSize = 4;
90	else
91	    subbandSize = [];   % BWP < 24 PRBs: no subbands
92	end
93	
94	% ── Shared struct for nrCQISelect (Rel-19, now supported) ────────────────
95	cqiCfg.NSizeBWP        = carrier.NSizeGrid;
96	cqiCfg.NStartBWP       = 0;
97	cqiCfg.CodebookType    = 'typeI-SinglePanel-r19';
98	cqiCfg.PanelDimensions = panelDimensions;
99	cqiCfg.PMIMode         = pmiMode;
100	cqiCfg.SubbandSize     = subbandSize;
101	cqiCfg.CQIMode         = cqiMode;
102	cqiCfg.CQITable        = 'table1';
103	
104	% =========================================================================
105	%  APPROACH B: Full 128-Port SVD Upper Bound
106	%  CQI: ZF SINR per layer → threshold table (wideband SVD, no codebook grid)
107	% =========================================================================
108	[~, S_B, V_B]    = svd(H_wb, 'econ');
109	singVals_B       = diag(S_B);
110	snr_sv_B         = singVals_B.^2 / nVar_wb;
111	riThresh_B       = 0.1 * singVals_B(1);
112	ri_B             = min(sum(singVals_B > riThresh_B), nRxAntennas);
113	W_B              = V_B(:, 1:ri_B);
114	
115	H_eff_B = H_wb * W_B;
116	W_zf_B  = pinv(H_eff_B);
117	sinr_B  = zeros(ri_B, 1);
118	for lyr = 1:ri_B
119	    sig  = abs(W_zf_B(lyr,:) * H_eff_B(:,lyr))^2;
120	    intf = sum(abs(W_zf_B(lyr,:) * H_eff_B).^2) - sig;
121	    nse  = nVar_wb * norm(W_zf_B(lyr,:))^2;
122	    sinr_B(lyr) = sig / (intf + nse);
123	end
124	cqi_tbl = [-6.7,-4.7,-2.3,0.2,2.4,4.7,6.9,9.3,10.7,12.2,14.1,15.6,18.0,20.3,22.7];
125	sinr_B_dB = 10*log10(sinr_B);
126	cqi_B     = max(sum(mean(sinr_B_dB) >= cqi_tbl), 1);   % wideband scalar
127	cap_B     = sum(log2(1 + snr_sv_B(1:ri_B) / ri_B));
128	
129	fb.ri_B   = ri_B;
130	fb.cqi_B  = cqi_B;
131	fb.cap_B  = cap_B;
132	fb.W_B    = W_B;
133	fb.sinr_B = sinr_B;   % [ri_B x 1] per-layer wideband ZF SINR (linear)
134	
135	% =========================================================================
136	%  APPROACH C: Rel-19 Mode A
137	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
138	%  CQI: nrCQISelect (L2SM/MIESM) — now supports typeI-SinglePanel-r19
139	% =========================================================================
140	riCfg_C.NSizeBWP        = carrier.NSizeGrid;
141	riCfg_C.NStartBWP       = 0;
142	riCfg_C.CodebookType    = 'typeI-SinglePanel-r19';
143	riCfg_C.PanelDimensions = panelDimensions;
144	riCfg_C.CodebookMode    = 1;
145	riCfg_C.PMIMode         = pmiMode;
146	riCfg_C.SubbandSize     = subbandSize;
147	[ri_C, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_C, H_4d, nVar_wb);
148	
149	cqiCfg_C             = cqiCfg;
150	cqiCfg_C.CodebookMode = 1;
151	[cqi_C_vec, ~, ~, pmiInfo_C] = nr5g.internal.nrCQISelect( ...
152	    carrier, csirs{1}, cqiCfg_C, ri_C, H_4d, nVar_wb);
153	% cqi_C_vec: row 1 = wideband, rows 2..end = per-subband (when CQIMode='Subband')
154	if strcmpi(cqiMode, 'Subband')
155	    cqi_C = cqi_C_vec;   % full vector [1+numSB x 1]
156	else
157	    cqi_C = cqi_C_vec(1);
158	end
159	W_C   = pmiInfo_C.W(:,:,1);   % first subband precoder for wideband capacity approx
160	cap_C = real(log2(det(eye(nRxAntennas) + ...
161	    (1/nVar_wb) * (H_wb*W_C*(H_wb*W_C)'))));
162	
163	fb.ri_C        = ri_C;
164	fb.cqi_C       = cqi_C;
165	fb.cap_C       = cap_C;
166	fb.W_C         = W_C;
167	fb.sinrPerRE_C = pmiInfo_C.SINRPerREPMI;
168	
169	% =========================================================================
170	%  APPROACH D: Rel-19 Mode B
171	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
172	%  CQI: nrCQISelect (L2SM/MIESM) — typeI-SinglePanel-r19
173	% =========================================================================
174	riCfg_D.NSizeBWP        = carrier.NSizeGrid;
175	riCfg_D.NStartBWP       = 0;
176	riCfg_D.CodebookType    = 'typeI-SinglePanel-r19';
177	riCfg_D.PanelDimensions = panelDimensions;
178	riCfg_D.CodebookMode    = 2;
179	riCfg_D.PMIMode         = pmiMode;
180	riCfg_D.SubbandSize     = subbandSize;
181	[ri_D, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_D, H_4d, nVar_wb);
182	
183	cqiCfg_D             = cqiCfg;
184	cqiCfg_D.CodebookMode = 2;
185	% Mode B beam group (i1) is always wideband (spec constraint).
186	% Co-phase (i2) follows pmiMode: 'Subband' activates Phase 2 per-subband
187	% co-phase in nrPMIReport, giving consistent W between RI and CQI steps.
188	cqiCfg_D.PMIMode      = pmiMode;
189	[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
190	    carrier, csirs{1}, cqiCfg_D, ri_D, H_4d, nVar_wb);
191	% cqi_D_vec: row 1 = wideband, rows 2..end = per-subband (when CQIMode='Subband')
192	if strcmpi(cqiMode, 'Subband')
193	    cqi_D = cqi_D_vec;   % full vector [1+numSB x 1]
194	else
195	    cqi_D = cqi_D_vec(1);
196	end
197	W_D   = pmiInfo_D.W(:,:,1);   % first subband precoder for wideband capacity approx
198	cap_D = real(log2(det(eye(nRxAntennas) + ...
199	    (1/nVar_wb) * (H_wb*W_D*(H_wb*W_D)'))));
200	
201	fb.ri_D        = ri_D;
202	fb.cqi_D       = cqi_D;
203	fb.cap_D       = cap_D;
204	fb.W_D         = W_D;
205	fb.sinrPerRE_D = pmiInfo_D.SINRPerREPMI;
206	
207	% =========================================================================
208	%  APPROACH E: Refined eTypeII (TS 38.214 §5.2.2.2.5a, Rel-19, 128 ports)
209	%  ThangTQ23_128T128R_eTypeII_Rel19
210	%
211	%  L=2 (PC 1/2): nrRISelect + nrCQISelect via nrPMIReport — spec-accurate,
212	%                C(1024,2)≈31K entries, fits memory, CQI from L2SM.
213	%  L≥4 (PC 3-8): greedy DFT beam selection — avoids OOM of exhaustive
214	%                search (C(1024,4)≈46×10^9 entries × 128×4 → >5 GB).
215	%                CQI via wideband ZF SINR (same method as Approach B).
216	% =========================================================================
217	L_tableE = [2 2 4 4 4 4 6 6];
218	L_E      = L_tableE(paramCombE);
219	maxRankE = min(nRxAntennas, 4);
220	if paramCombE >= 7
221	    maxRankE = min(nRxAntennas, 2);   % PC 7/8: pv(v=3,4)="-" → maxRank=2
222	end
223	
224	if L_E <= 2
225	    % ── L=2: full toolbox pipeline (nrPMIReport exhaustive, tractable) ───
226	    riCfg_E.NSizeBWP                         = carrier.NSizeGrid;
227	    riCfg_E.NStartBWP                        = 0;
228	    riCfg_E.CodebookType                     = 'eTypeII-r19';
229	    riCfg_E.PanelDimensions                  = panelDimensions;
230	    riCfg_E.ParameterCombination             = paramCombE;
231	    riCfg_E.NumberOfPMISubbandsPerCQISubband = 1;
232	    riCfg_E.PMIMode                          = pmiMode;
233	    riCfg_E.SubbandSize                      = subbandSize;
234	    [ri_E, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_E, H_4d, nVar_wb);
235	
236	    cqiCfg_E.NSizeBWP                         = carrier.NSizeGrid;
237	    cqiCfg_E.NStartBWP                        = 0;
238	    cqiCfg_E.CodebookType                     = 'eTypeII-r19';
239	    cqiCfg_E.PanelDimensions                  = panelDimensions;
240	    cqiCfg_E.ParameterCombination             = paramCombE;
241	    cqiCfg_E.NumberOfPMISubbandsPerCQISubband = 1;
242	    cqiCfg_E.PMIMode                          = pmiMode;
243	    cqiCfg_E.SubbandSize                      = subbandSize;
244	    cqiCfg_E.CQIMode                          = cqiMode;
245	    cqiCfg_E.CQITable                         = 'table1';
246	    % Retry loop: wideband RI selection may pick a rank that the subband
247	    % eTypeII quantization (pv, L) can't represent → nrCQISelect returns NaN.
248	    % Decrement ri_E until a valid CQI is obtained.
249	    cqi_E_vec = NaN;
250	    while ri_E >= 1 && isnan(cqi_E_vec(1))
251	        [cqi_E_vec, ~, ~, pmiInfo_E] = nr5g.internal.nrCQISelect( ...
252	            carrier, csirs{1}, cqiCfg_E, ri_E, H_4d, nVar_wb);
253	        if isnan(cqi_E_vec(1))
254	            ri_E = ri_E - 1;
255	        end
256	    end
257	    if strcmpi(cqiMode, 'Subband')
258	        cqi_E = cqi_E_vec;
259	    else
260	        cqi_E = cqi_E_vec(1);
261	    end
262	    W_E         = pmiInfo_E.W(:,:,1);
263	    cap_E       = real(log2(det(eye(nRxAntennas) + ...
264	        (1/nVar_wb) * (H_wb*W_E*(H_wb*W_E)'))));
265	    sinrPerRE_E = pmiInfo_E.SINRPerREPMI;
266	
267	else
268	    % ── L≥4: greedy DFT beam selection (OOM-safe) ────────────────────────
269	    % nrPMIReport pre-allocates Precoders(nTx,nLayers,C(nGrid,L),q1,q2):
270	    % C(1024,4)×128×4 entries > 5 GB → OOM. Greedy: O(L×nGrid) per rank.
271	    bestCap_E = -Inf;
272	    ri_E = 1;
273	    W_E  = zeros(nTxAntennas, 1);
274	    for rank_E = 1:maxRankE
275	        W_try  = greedyEType2R19Precoder(H_wb, panelDimensions, L_E, rank_E);
276	        HW_try = H_wb * W_try;
277	        cap_try = real(log2(det(eye(nRxAntennas) + ...
278	            (1/nVar_wb) * (HW_try * HW_try'))));
279	        if cap_try > bestCap_E
280	            bestCap_E = cap_try;  ri_E = rank_E;  W_E = W_try;
281	        end
282	    end
283	    cap_E = bestCap_E;
284	
285	    % SINR per layer: ZF receiver on wideband H (same as Approach B)
286	    H_eff_E = H_wb * W_E;
287	    W_zf_E  = pinv(H_eff_E);
288	    sinr_E  = zeros(ri_E, 1);
289	    for lyr = 1:ri_E
290	        sig  = abs(W_zf_E(lyr,:) * H_eff_E(:,lyr))^2;
291	        intf = sum(abs(W_zf_E(lyr,:) * H_eff_E).^2) - sig;
292	        nse  = nVar_wb * norm(W_zf_E(lyr,:))^2;
293	        sinr_E(lyr) = sig / (intf + nse);
294	    end
295	
296	    % CQI: wideband SINR → table lookup (same cqi_tbl as Approach B)
297	    sinr_E_dB = 10*log10(max(sinr_E, 1e-10));
298	    cqi_E     = max(sum(mean(sinr_E_dB) >= cqi_tbl), 1);
299	
300	    % sinrPerRE_E: replicate wideband SINR [nRE × ri_E] for computeMetrics
301	    sinrPerRE_E = repmat(sinr_E.', carrier.NSizeGrid * 12, 1);
302	end
303	
304	fb.ri_E        = ri_E;
305	fb.cqi_E       = cqi_E;
306	fb.cap_E       = cap_E;
307	fb.W_E         = W_E;
308	fb.sinrPerRE_E = sinrPerRE_E;
309	
310	end
311	
312	% =========================================================================
313	%  LOCAL HELPER: Greedy DFT beam selection for eTypeII-r19 (L≥4 path)
314	%  ThangTQ23_128T128R_eTypeII_Rel19
315	% =========================================================================
316	function W = greedyEType2R19Precoder(H_wb, panelDimensions, L, nLayers)
317	%GREEDYETYPE2R19PRECODER  eTypeII-r19 precoder via greedy DFT beam selection.
318	%
319	%  Dual-pol DFT codebook structure per TS 38.214 §5.2.2.2.5:
320	%    W = W1 * W2
321	%  W1: L DFT beams per polarization selected by greedy matching pursuit.
322	%  W2: combining coefficients from projected SVD.
323	%
324	%  Inputs:
325	%    H_wb          - [nRx × 2*N1*N2] wideband channel matrix
326	%    panelDimensions - [Ng, N1, N2]
327	%    L             - number of beams
328	%    nLayers       - number of spatial layers (rank)
329	%
330	%  Output:
331	%    W - [2*N1*N2 × nLayers] unit-Frobenius-norm precoder (||W||_F = 1)
332	
333	    N1 = panelDimensions(2);
334	    N2 = panelDimensions(3);
335	    O1 = 4;  O2 = 4;          % fixed oversampling per §5.2.2.2.5a
336	    nPerPol = N1 * N2;
337	
338	    % ── Oversampled DFT grid A [nPerPol × O1*N1*O2*N2] ──────────────────
339	    % u_{n1,n2} = a_{N1,O1}(n1) ⊗ a_{N2,O2}(n2)  (TS 38.214 §5.2.2.2.3)
340	    k1 = (0:N1-1)';  k2 = (0:N2-1)';
341	    nGrid = N1*O1 * N2*O2;
342	    A = zeros(nPerPol, nGrid);
343	    col = 0;
344	    for n1 = 0:N1*O1-1
345	        a1 = exp(1j*2*pi*n1*k1/(N1*O1)) / sqrt(N1);
346	        for n2 = 0:N2*O2-1
347	            col = col + 1;
348	            a2 = exp(1j*2*pi*n2*k2/(N2*O2)) / sqrt(N2);
349	            A(:, col) = kron(a1, a2);
350	        end
351	    end
352	
353	    % ── Greedy matching pursuit — shared beams for both polarizations ─────
354	    H1 = H_wb(:, 1:nPerPol);        % pol-1  [nRx × nPerPol]
355	    H2 = H_wb(:, nPerPol+1:end);    % pol-2  [nRx × nPerPol]
356	    R1 = H1;  R2 = H2;
357	    B  = zeros(nPerPol, L);
358	    for l = 1:L
359	        scores     = sum(abs(R1*A).^2 + abs(R2*A).^2, 1);
360	        [~, best]  = max(scores);
361	        a_sel      = A(:, best);
362	        B(:, l)    = a_sel;
363	        R1 = R1 - (R1 * a_sel) * a_sel';   % orthogonal deflation
364	        R2 = R2 - (R2 * a_sel) * a_sel';
365	    end
366	
367	    % ── W1: dual-pol block-diagonal [2*nPerPol × 2L] ─────────────────────
368	    W1 = [B, zeros(nPerPol,L); zeros(nPerPol,L), B];
369	
370	    % ── W2: combining coefficients via projected SVD [2L × nLayers] ──────
371	    [~, ~, Vp] = svd(H_wb * W1, 'econ');
372	    W2 = Vp(:, 1:min(nLayers, size(Vp,2)));
373	
374	    % ── W = W1 * W2, unit Frobenius norm (||W||_F = 1) ───────────────────
375	    % Per TS 38.214 §5.2.2.2.5: W2 normalized s.t. ||W||_F=1 → total TX
376	    % power = 1, consistent with Approach B (sum log2(1+sv²/(r*nVar)))
377	    % and nrPMIReport output for Approach C/D.
378	    W = W1 * W2;
379	    W_fro = norm(W, 'fro');
380	    if W_fro > 1e-10
381	        W = W / W_fro;
382	    end
383	end
